  ('promotion-e3452428-moex-00065', 'promotion-e3452428', 'promotion-e3452428-moex-112-c4ffbd92', 'sub-promotion-e3452428-01', NULL, 'essay', '何謂都會治理？請說明我國當前都會治理的問題與解決之道。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:39+00:00", "source_pdf_sha1": "b2083a4225fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "102", "s": "0303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "地方政府與政治", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "一般民政"}'::jsonb, NULL),
  ('promotion-e3452428-moex-00066', 'promotion-e3452428', 'promotion-e3452428-moex-112-c4ffbd92', 'sub-promotion-e3452428-01', NULL, 'essay', '何謂審議民主？請問地方政府如何連結社區與大學，共同推動審議民
